"use client";

import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import React from "react";

const codeLines = [
  { text: "$ gunmetal setup", color: "#faf9f6", delay: 0 },
  { text: "✔ Linked Anthropic account", color: "#868584", delay: 0.5 },
  { text: "✔ Linked OpenRouter account", color: "#868584", delay: 0.7 },
  { text: "✔ Minted local key: gm_local_12345", color: "#868584", delay: 1.0 },
  { text: "", color: "", delay: 1.2 },
  { text: "$ export OPENAI_BASE_URL=http://127.0.0.1:4684/v1", color: "#faf9f6", delay: 1.5 },
  { text: "$ export OPENAI_API_KEY=gm_local_12345", color: "#faf9f6", delay: 1.8 },
  { text: "", color: "", delay: 2.0 },
  { text: "$ curl $OPENAI_BASE_URL/chat/completions \\", color: "#afaeac", delay: 2.3 },
  { text: '    -d \'{"model": "anthropic/claude-3.5-sonnet", "messages": [...]}\'', color: "#afaeac", delay: 2.4 }
];

export function HeroTerminal() {
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const mouseXSpring = useSpring(x, { stiffness: 100, damping: 30 });
  const mouseYSpring = useSpring(y, { stiffness: 100, damping: 30 });

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["6deg", "-6deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-6deg", "6deg"]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    const xPct = mouseX / width - 0.5;
    const yPct = mouseY / height - 0.5;
    x.set(xPct);
    y.set(yPct);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  return (
    <div 
      className="w-full max-w-4xl mx-auto"
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
    >
      <motion.div
        style={{
          rotateX,
          rotateY,
          transformStyle: "preserve-3d",
        }}
        className="rounded-[12px] border border-[rgba(226,226,226,0.15)] bg-[#161615] shadow-2xl overflow-hidden text-left relative"
      >
        {/* Terminal Header */}
        <div className="flex items-center px-4 py-3 border-b border-[rgba(226,226,226,0.08)] bg-[rgba(255,255,255,0.02)]">
          <div className="flex space-x-2">
            <div className="w-3 h-3 rounded-full bg-[#454545] border border-[rgba(255,255,255,0.05)]" />
            <div className="w-3 h-3 rounded-full bg-[#454545] border border-[rgba(255,255,255,0.05)]" />
            <div className="w-3 h-3 rounded-full bg-[#454545] border border-[rgba(255,255,255,0.05)]" />
          </div>
          <div className="mx-auto text-[12px] font-mono text-[#868584] tracking-wide flex items-center gap-2">
            <svg className="w-3.5 h-3.5 opacity-70" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 12h14M5 12a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v4a2 2 0 01-2 2M5 12a2 2 0 00-2 2v4a2 2 0 002 2h14a2 2 0 002-2v-4a2 2 0 00-2-2m-2-4h.01M17 16h.01" />
            </svg>
            gunmetal — node
          </div>
        </div>

        {/* Terminal Body */}
        <div className="p-6 md:p-8 font-mono text-[13px] md:text-[15px] leading-[1.7] overflow-x-auto whitespace-pre relative z-10">
           {codeLines.map((line, i) => (
             <motion.div 
                key={i}
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: line.delay + 0.8, duration: 0 }}
                style={{ color: line.color }}
                className="min-h-[1.7rem]"
             >
                {line.text}
             </motion.div>
           ))}
           <motion.div 
             initial={{ opacity: 0 }}
             animate={{ opacity: [0, 1, 0] }}
             transition={{ repeat: Infinity, duration: 0.8, ease: "linear", delay: 3.5 }}
             className="inline-block w-[8px] h-[16px] md:h-[18px] bg-[#faf9f6] mt-1 align-middle shadow-[0_0_8px_rgba(250,249,246,0.3)]"
           />
        </div>

        {/* Ambient Glow inside terminal */}
        <div className="absolute inset-0 bg-gradient-to-tr from-[rgba(250,249,246,0.015)] to-transparent pointer-events-none" />
      </motion.div>
    </div>
  );
}

args.content:
"use client";

import { motion, useMotionTemplate, useMotionValue } from "framer-motion";
import { MouseEvent } from "react";
import { HeroTerminal } from "@/components/ui/HeroTerminal";
import { Button } from "@/components/ui/Button";

export function Hero() {
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  function handleMouseMove({ currentTarget, clientX, clientY }: MouseEvent) {
    const { left, top } = currentTarget.getBoundingClientRect();
    mouseX.set(clientX - left);
    mouseY.set(clientY - top);
  }

  return (
    <section 
      className="relative min-h-[100vh] w-full flex flex-col items-center justify-center overflow-hidden pt-32 pb-24"
      onMouseMove={handleMouseMove}
      style={{ background: "var(--bg)" }}
    >
      {/* Dynamic Background Mesh / Spotlight */}
      <motion.div
        className="pointer-events-none absolute -inset-px opacity-60 transition duration-300 z-0"
        style={{
          background: useMotionTemplate`
            radial-gradient(
              750px circle at ${mouseX}px ${mouseY}px,
              rgba(250, 249, 246, 0.025),
              transparent 80%
            )
          `,
        }}
      />

      {/* Subtle Grid Pattern for Depth */}
      <div 
        className="absolute inset-0 pointer-events-none opacity-[0.02] z-0"
        style={{
          backgroundImage: `
            linear-gradient(to right, #faf9f6 1px, transparent 1px),
            linear-gradient(to bottom, #faf9f6 1px, transparent 1px)
          `,
          backgroundSize: "4rem 4rem",
          maskImage: "radial-gradient(ellipse at center, black, transparent 80%)",
          WebkitMaskImage: "radial-gradient(ellipse at center, black, transparent 80%)"
        }}
      />

      <div className="relative z-10 container mx-auto px-6 flex flex-col items-center text-center">
        {/* Editorial Brand Tag */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
          className="mb-8 inline-flex items-center rounded-[6px] border border-[rgba(226,226,226,0.15)] bg-[rgba(255,255,255,0.03)] px-3 py-1 text-[12px] uppercase tracking-[2.4px] text-[#faf9f6] backdrop-blur-md shadow-[0_4px_12px_rgba(0,0,0,0.1)] transition-colors hover:bg-[rgba(255,255,255,0.06)] cursor-default"
        >
          <span className="mr-3 h-1.5 w-1.5 rounded-full bg-[#afaeac] opacity-90 shadow-[0_0_8px_rgba(250,249,246,0.4)] relative">
            <span className="absolute inset-0 rounded-full bg-[#faf9f6] animate-ping opacity-50" />
          </span>
          The Gunmetal Super App
        </motion.div>

        {/* Majestic Typography matching Warp DESIGN.md */}
        <h1 
          className="mb-6 max-w-5xl text-[56px] font-normal leading-[1.00] tracking-[-2.4px] text-[#faf9f6] md:text-[80px]"
          style={{ fontFamily: "var(--font-matter)" }}
        >
          <motion.span 
            initial={{ opacity: 0, y: 25 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.9, delay: 0.1, ease: [0.16, 1, 0.3, 1] }}
            className="block"
          >
            The middleman layer
          </motion.span>
          <motion.span 
            initial={{ opacity: 0, y: 25 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.9, delay: 0.2, ease: [0.16, 1, 0.3, 1] }}
            className="block text-[#868584]"
          >
            for AI inference.
          </motion.span>
        </h1>

        <motion.p
          initial={{ opacity: 0, y: 15 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.9, delay: 0.4, ease: [0.16, 1, 0.3, 1] }}
          className="mx-auto mb-10 max-w-[640px] text-[18px] md:text-[20px] text-[#afaeac] leading-[1.40] tracking-[-0.2px]"
          style={{ fontFamily: "var(--font-matter)" }}
        >
          Connect providers you already use, create local Gunmetal keys, point your apps at <code className="px-1.5 py-0.5 rounded bg-[rgba(255,255,255,0.06)] text-[#faf9f6] font-mono text-[15px] border border-[rgba(255,255,255,0.05)]">127.0.0.1:4684</code>, and use AI anywhere.
        </motion.p>

        {/* CTA Actions */}
        <motion.div
          initial={{ opacity: 0, y: 15 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.5, ease: [0.16, 1, 0.3, 1] }}
          className="flex flex-col items-center gap-6 sm:flex-row relative z-20"
        >
          <Button 
            className="relative overflow-hidden group h-[50px] rounded-[50px] bg-[#353534] px-8 text-[16px] font-medium text-[#afaeac] transition-all hover:bg-[#454545] hover:text-[#faf9f6]"
            onClick={() => navigator.clipboard.writeText("npm i -g @dhruv2mars/gunmetal")}
          >
            <span className="relative z-10 flex items-center gap-2">
              <svg className="w-4 h-4 opacity-70 group-hover:opacity-100 transition-opacity" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
              </svg>
              npm i -g @dhruv2mars/gunmetal
            </span>
            <div className="absolute inset-0 h-full w-full bg-gradient-to-r from-transparent via-[rgba(255,255,255,0.06)] to-transparent -translate-x-[100%] group-hover:animate-[shimmer_1.5s_infinite]" />
          </Button>
          <a href="/docs" className="text-[16px] text-[#868584] underline decoration-[rgba(134,133,132,0.3)] underline-offset-4 transition-colors hover:text-[#faf9f6] hover:decoration-[rgba(250,249,246,0.5)] px-4 py-2 font-medium" style={{ fontFamily: "var(--font-matter)" }}>
            Read the docs
          </a>
        </motion.div>

        {/* Floating Interactive Terminal Widget */}
        <motion.div
          initial={{ opacity: 0, y: 60, scale: 0.95 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          transition={{ duration: 1.2, delay: 0.7, ease: [0.16, 1, 0.3, 1] }}
          className="w-full mt-20 lg:mt-24 relative z-10 perspective-[1200px]"
        >
          <HeroTerminal />
        </motion.div>
      </div>

      <style dangerouslySetInnerHTML={{__html: `
        @keyframes shimmer {
          100% { transform: translateX(100%); }
        }
      `}} />
    </section>
  );
}

