"use client";

import { motion } from "framer-motion";
import { Aurora } from "@/components/ui/Aurora";
import { Button } from "@/components/ui/Button";

export function Hero() {
  return (
    <section className="relative min-h-[90vh] w-full flex items-center justify-center overflow-hidden" style={{ background: "var(--bg)" }}>
      {/* Background */}
      <Aurora className="z-0" />

      {/* Veil / Vignette */}
      <div className="absolute inset-0 bg-gradient-to-b from-transparent via-[var(--bg)]/50 to-[var(--bg)] z-0 pointer-events-none" />

      {/* Content */}
      <div className="relative z-10 container mx-auto px-6 flex flex-col items-center text-center pt-20">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, ease: [0.16, 1, 0.3, 1] }}
          className="mb-6 inline-flex items-center rounded-full border border-[rgba(226,226,226,0.1)] bg-[rgba(255,255,255,0.03)] px-3 py-1 text-[11px] uppercase tracking-[2.4px] text-[#868584]"
        >
          <span className="mr-2 h-1.5 w-1.5 rounded-full bg-[#afaeac] opacity-70" />
          The Gunmetal Super App
        </motion.div>

        <h1 
          className="mb-8 max-w-4xl text-5xl font-normal leading-[1.05] tracking-[-0.04em] text-[#faf9f6] md:text-7xl lg:text-[80px]"
          style={{ fontFamily: "var(--font-matter)" }}
        >
          <span className="block">The middleman layer</span>
          <span className="block text-[#afaeac]">for AI inference.</span>
        </h1>

        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1, delay: 0.4 }}
          className="mx-auto mb-10 max-w-2xl text-lg text-[#afaeac] md:text-[20px] leading-relaxed"
          style={{ fontFamily: "var(--font-matter)" }}
        >
          Connect providers you already use, create local Gunmetal keys, point your apps at <code className="px-1.5 py-0.5 rounded bg-[rgba(255,255,255,0.05)] text-[#faf9f6] font-mono text-[14px]">127.0.0.1:4684</code>, and use AI anywhere.
        </motion.p>

        <motion.div
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.6 }}
          className="flex flex-col items-center gap-4 sm:flex-row"
        >
          <Button 
            className="h-14 rounded-full bg-[#353534] px-8 text-[16px] font-medium text-[#afaeac] transition-all hover:bg-[#454545] hover:text-[#faf9f6] hover:scale-[1.02]"
            onClick={() => navigator.clipboard.writeText("npm i -g @dhruv2mars/gunmetal")}
          >
            npm i -g @dhruv2mars/gunmetal
          </Button>
          <a href="/docs" className="text-[16px] text-[#868584] underline decoration-[rgba(134,133,132,0.3)] underline-offset-4 transition-colors hover:text-[#faf9f6] hover:decoration-[rgba(250,249,246,0.5)] px-4 py-2">
            Read the docs
          </a>
        </motion.div>
      </div>
    </section>
  );
}

