"use client";

import { motion } from "framer-motion";

export function SplitText({ 
  children, 
  delay = 0, 
  className = "" 
}: { 
  children: string, 
  delay?: number, 
  className?: string 
}) {
  const words = children.split(" ");
  return (
    <span className={className}>
      {words.map((word, i) => (
