"use client";

import { motion, useMotionValue, useSpring, useTransform } from "framer-motion";
import React from "react";

const codeLines = [
  { text: "$ gunmetal setup", color: "#faf9f6", delay: 0 },
  { text: "✔ Linked Anthropic account", color: "#868584", delay: 0.5 },
  { text: "✔ Linked OpenRouter account", color: "#868584", delay: 0.7 },
  { text: "✔ Minted local key: gm_local_12345", color: "#868584", delay: 1.0 },
  { text: "", color: "", delay: 1.2 },
  { text: "$ export OPENAI_BASE_URL=http://127.0.0.1:4684/v1", color: "#faf9f6", delay: 1.5 },
  { text: "$ export OPENAI_API_KEY=gm_local_12345", color: "#faf9f6", delay: 1.8 },
  { text: "", color: "", delay: 2.0 },
  { text: "$ curl $OPENAI_BASE_URL/chat/completions \\", color: "#afaeac", delay: 2.3 },
  { text: '    -d \'{"model": "anthropic/claude-3.5-sonnet", "messages": [...]}\'', color: "#afaeac", delay: 2.4 }
];

export function HeroTerminal() {
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const mouseXSpring = useSpring(x, { stiffness: 100, damping: 30 });
  const mouseYSpring = useSpring(y, { stiffness: 100, damping: 30 });

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["6deg", "-6deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-6deg", "6deg"]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    const xPct = mouseX / width - 0.5;
    const yPct = mouseY / height - 0.5;
    x.set(xPct);
    y.set(yPct);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  return (
    <div 
      className="w-full max-w-4xl mx-auto"
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
    >
      <motion.div
        style={{
          rotateX,
          rotateY,
          transformStyle: "preserve-3d",
        }}
        className="rounded-[12px] border border-[rgba(226,226,226,0.15)] bg-[#161615] shadow-2xl overflow-hidden text-left relative"
      >
        {/* Terminal Header */}
        <div className="flex items-center px-4 py-3 border-b border-[rgba(226,226,226,0.08)] bg-[rgba(255,255,255,0.02)]">
          <div className="flex space-x-2">
            <div className="w-3 h-3 rounded-full bg-[#454545] border border-[rgba(255,255,255,0.05)]" />
            <div className="w-3 h-3 rounded-full bg-[#454545] border border-[rgba(255,255,255,0.05)]" />
            <div className="w-3 h-3 rounded-full bg-[#454545] border border-[rgba(255,255,255,0.05)]" />
          </div>
          <div className="mx-auto text-[12px] font-mono text-[#868584] tracking-wide flex items-center gap-2">
            <svg className="w-3.5 h-3.5 opacity-70" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 12h14M5 12a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v4a2 2 0 01-2 2M5 12a2 2 0 00-2 2v4a2 2 0 002 2h14a2 2 0 002-2v-4a2 2 0 00-2-2m-2-4h.01M17 16h.01" />
            </svg>
            gunmetal — node
          </div>
        </div>

        {/* Terminal Body */}
        <div className="p-6 md:p-8 font-mono text-[13px] md:text-[15px] leading-[1.7] overflow-x-auto whitespace-pre relative z-10">
           {codeLines.map((line, i) => (
             <motion.div 
                key={i}
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: line.delay + 0.8, duration: 0 }}
                style={{ color: line.color }}
                className="min-h-[1.7rem]"
             >
                {line.text}
             </motion.div>
           ))}
           <motion.div 
             initial={{ opacity: 0 }}
             animate={{ opacity: [0, 1, 0] }}
             transition={{ repeat: Infinity, duration: 0.8, ease: "linear", delay: 3.5 }}
             className="inline-block w-[8px] h-[16px] md:h-[18px] bg-[#faf9f6] mt-1 align-middle shadow-[0_0_8px_rgba(250,249,246,0.3)]"
           />
        </div>

        {/* Ambient Glow inside terminal */}
        <div className="absolute inset-0 bg-gradient-to-tr from-[rgba(250,249,246,0.015)] to-transparent pointer-events-none" />
      </motion.div>
    </div>
  );
}

