"use client";

import { motion, useMotionTemplate, useMotionValue, useSpring, useTransform } from "framer-motion";
import React, { useState } from "react";

const terminalLines = [
  { type: 'command', prefix: "$ ", text: "gunmetal setup", delay: 0 },
  { type: 'success', text: "✔ Linked Anthropic account", color: "#868584", delay: 0.6 },
  { type: 'success', text: "✔ Linked OpenRouter account", color: "#868584", delay: 0.8 },
  { type: 'success', text: "✔ Minted local key: gm_local_12345", color: "#868584", delay: 1.1 },
  { type: 'empty', delay: 1.3 },
  { type: 'command', prefix: "$ ", text: "export OPENAI_BASE_URL=http://127.0.0.1:4684/v1", delay: 1.6 },
  { type: 'command', prefix: "$ ", text: "export OPENAI_API_KEY=gm_local_12345", delay: 1.9 },
  { type: 'empty', delay: 2.1 },
  { type: 'command', prefix: "$ ", text: "curl $OPENAI_BASE_URL/chat/completions \\", delay: 2.4 },
  { type: 'code', text: "    -d '{\"model\": \"anthropic/claude-3.5-sonnet\", \"messages\": [{\"role\":\"user\", \"content\":\"say ok\"}]}'", delay: 2.6 },
  { type: 'empty', delay: 2.8 },
  { type: 'json', text: "{\"id\": \"chatcmpl-123\", \"choices\": [{\"message\": {\"role\": \"assistant\", \"content\": \"ok\"}}]}", delay: 3.4 },
];

export function HeroTerminal() {
  const x = useMotionValue(0);
  const y = useMotionValue(0);

  const mouseXSpring = useSpring(x, { stiffness: 100, damping: 30 });
  const mouseYSpring = useSpring(y, { stiffness: 100, damping: 30 });

  const rotateX = useTransform(mouseYSpring, [-0.5, 0.5], ["6deg", "-6deg"]);
  const rotateY = useTransform(mouseXSpring, [-0.5, 0.5], ["-6deg", "6deg"]);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    const rect = e.currentTarget.getBoundingClientRect();
    const width = rect.width;
    const height = rect.height;
    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;
    x.set(mouseX / width - 0.5);
    y.set(mouseY / height - 0.5);
  };

  const handleMouseLeave = () => {
    x.set(0);
    y.set(0);
  };

  return (
    <div 
      className="w-full max-w-4xl mx-auto perspective-[2000px] group"
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
    >
      <motion.div
        style={{
          rotateX,
          rotateY,
          transformStyle: "preserve-3d",
        }}
        className="rounded-[14px] border border-[rgba(226,226,226,0.1)] bg-[#111110] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.6)] text-left relative transition-all duration-300"
      >
        {/* Dynamic Edge Glow overlay (simulates BorderBeam) */}
        <div className="absolute -inset-[1px] rounded-[15px] pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-500 overflow-hidden mix-blend-screen z-0">
           <motion.div 
             animate={{ rotate: 360 }}
             transition={{ duration: 10, repeat: Infinity, ease: "linear" }}
             className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-[200%] aspect-square"
             style={{
                background: "conic-gradient(from 0deg, transparent 60%, rgba(250,249,246,0.3) 100%)"
             }}
           />
        </div>

        {/* Ambient Inner Light */}
        <motion.div
          className="absolute inset-0 pointer-events-none rounded-[14px] opacity-0 group-hover:opacity-20 transition-opacity duration-500 mix-blend-overlay z-20"
          style={{
            background: useMotionTemplate`radial-gradient(1200px circle at ${useTransform(mouseXSpring, [-0.5, 0.5], ["0%", "100%"])} ${useTransform(mouseYSpring, [-0.5, 0.5], ["0%", "100%"])}, rgba(255,255,255,0.4), transparent 40%)`
          }}
        />

        {/* Glass Content Wrapper */}
        <div className="relative rounded-[13px] bg-[#161615]/90 backdrop-blur-md overflow-hidden z-10">

          {/* Terminal Header */}
          <div className="flex items-center px-4 py-[14px] border-b border-[rgba(226,226,226,0.06)] bg-[rgba(255,255,255,0.015)] shadow-[0_1px_2px_rgba(0,0,0,0.2)]">
            <div className="flex space-x-2 group/controls cursor-pointer">
              <div className="w-3 h-3 rounded-full bg-[#454545] border border-[rgba(255,255,255,0.05)] transition-colors group-hover/controls:bg-[#ff5f56]" />
              <div className="w-3 h-3 rounded-full bg-[#454545] border border-[rgba(255,255,255,0.05)] transition-colors group-hover/controls:bg-[#ffbd2e]" />
              <div className="w-3 h-3 rounded-full bg-[#454545] border border-[rgba(255,255,255,0.05)] transition-colors group-hover/controls:bg-[#27c93f]" />
            </div>
            <div className="mx-auto text-[12px] font-mono text-[#868584] tracking-[0.5px] flex items-center gap-2 opacity-80">
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M5 12h14M5 12a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v4a2 2 0 01-2 2M5 12a2 2 0 00-2 2v4a2 2 0 002 2h14a2 2 0 002-2v-4a2 2 0 00-2-2m-2-4h.01M17 16h.01" />
              </svg>
              gunmetal — node
            </div>
          </div>

          {/* Terminal Body */}
          <div className="p-6 md:p-8 font-mono text-[13px] md:text-[15px] leading-[1.7] overflow-x-auto whitespace-pre">
            {terminalLines.map((line, i) => (
              <motion.div 
                  key={i}
                  initial={{ opacity: 0, y: 5 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: (line.delay || 0) + 1.2, duration: 0.1 }}
                  className="min-h-[1.7rem]"
              >
                  {line.type === 'command' && (
                    <>
                      <span className="text-[#868584]">{line.prefix}</span>
                      <span className="text-[#faf9f6]">{line.text}</span>
                    </>
                  )}
                  {line.type === 'success' && (
                    <span className="text-[#868584]">{line.text}</span>
                  )}
                  {line.type === 'code' && (
                    <span className="text-[#afaeac] opacity-90">{line.text}</span>
                  )}
                  {line.type === 'json' && (
                    <span className="text-[#afaeac] opacity-70">{line.text}</span>
                  )}
              </motion.div>
            ))}
            <motion.div 
              initial={{ opacity: 0 }}
              animate={{ opacity: [0, 1, 0] }}
              transition={{ repeat: Infinity, duration: 0.9, ease: "linear", delay: 4.6 }}
              className="inline-block w-[8px] h-[16px] md:h-[18px] bg-[rgba(250,249,246,0.9)] mt-1 align-middle shadow-[0_0_10px_rgba(250,249,246,0.4)]"
            />
          </div>

          {/* Ambient Grid Background inside terminal */}
          <div className="absolute inset-0 z-[-1] pointer-events-none opacity-[0.02]"
               style={{ backgroundImage: 'linear-gradient(to right, #faf9f6 1px, transparent 1px), linear-gradient(to bottom, #faf9f6 1px, transparent 1px)', backgroundSize: '1.5rem 1.5rem' }} />
        </div>
      </motion.div>
    </div>
  );
}

