"use client";

import { motion, useMotionTemplate, useMotionValue, useSpring } from "framer-motion";
import { MouseEvent, useEffect, useState } from "react";
import { HeroTerminal } from "@/components/ui/HeroTerminal";
import { SplitText } from "@/components/ui/SplitText";
import { MagneticButton } from "@/components/ui/MagneticButton";
import { Particles } from "@/components/ui/Particles";

export function Hero() {
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  // Add a slight spring to the light tracker for cinematic fluidity
  const smoothMouseX = useSpring(mouseX, { stiffness: 50, damping: 20 });
  const smoothMouseY = useSpring(mouseY, { stiffness: 50, damping: 20 });

  function handleMouseMove({ currentTarget, clientX, clientY }: MouseEvent) {
    const { left, top } = currentTarget.getBoundingClientRect();
    mouseX.set(clientX - left);
    mouseY.set(clientY - top);
  }

  // Ensure initial render matches server by mounting effects only on client
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  return (
    <section 
      className="relative min-h-[100vh] w-full flex flex-col items-center justify-center overflow-hidden pt-32 pb-24"
      onMouseMove={handleMouseMove}
      style={{ background: "var(--bg)" }}
    >
      {/* 1. Base Layer: The Void (Particles) */}
      {mounted && <Particles />}

      {/* 2. Middle Layer: Spring-tracked cinematic spotlight */}
      <motion.div
        className="pointer-events-none absolute inset-0 transition duration-300 z-0 opacity-80 mix-blend-screen"
        style={{
          background: useMotionTemplate`
            radial-gradient(
              800px circle at ${smoothMouseX}px ${smoothMouseY}px,
              rgba(250, 249, 246, 0.04),
              transparent 70%
            )
          `,
        }}
      />

      {/* 3. Texture Layer: Deep abstract perspective grid */}
      <div 
        className="absolute inset-0 pointer-events-none opacity-[0.015] z-0"
        style={{
          backgroundImage: `
            linear-gradient(to right, #faf9f6 1px, transparent 1px),
            linear-gradient(to bottom, #faf9f6 1px, transparent 1px)
          `,
          backgroundSize: "4rem 4rem",
          maskImage: "radial-gradient(ellipse at 50% -20%, black 10%, transparent 70%)",
          WebkitMaskImage: "radial-gradient(ellipse at 50% -20%, black 10%, transparent 70%)",
          transform: "perspective(1000px) rotateX(60deg) scale(2)",
          transformOrigin: "top center"
        }}
      />

      <div className="relative z-10 container mx-auto px-6 flex flex-col items-center text-center">
        {/* Editorial Brand Tag */}
        <motion.div
          initial={{ opacity: 0, scale: 0.9, filter: "blur(4px)" }}
          animate={{ opacity: 1, scale: 1, filter: "blur(0px)" }}
          transition={{ duration: 1.2, ease: [0.16, 1, 0.3, 1] }}
          className="mb-10 inline-flex items-center rounded-sm px-3 py-1.5 text-[11px] uppercase tracking-[3px] text-[#faf9f6] bg-[rgba(255,255,255,0.02)] border border-[rgba(255,255,255,0.05)] backdrop-blur-md cursor-default"
        >
          <span className="mr-3 h-1 w-1 rounded-full bg-[#afaeac] relative shadow-[0_0_6px_rgba(250,249,246,0.6)]">
            <span className="absolute inset-0 rounded-full bg-[#faf9f6] animate-ping opacity-70" />
          </span>
          The Gunmetal Super App
        </motion.div>

        {/* Majestic Typography using SplitText for staggered cinematic reveal */}
        <h1 
          className="mb-8 max-w-[1000px] text-[52px] sm:text-[64px] md:text-[88px] font-normal leading-[0.95] tracking-[-0.04em] text-[#faf9f6]"
          style={{ fontFamily: "var(--font-matter)" }}
        >
          <SplitText className="block text-[#faf9f6]" delay={0.2}>
            The middleman layer
          </SplitText>
          <SplitText className="block text-[#868584] mt-2 md:mt-0" delay={0.4}>
            for AI inference.
          </SplitText>
        </h1>

        <motion.p
          initial={{ opacity: 0, y: 15, filter: "blur(4px)" }}
          animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
          transition={{ duration: 1.2, delay: 0.8, ease: [0.16, 1, 0.3, 1] }}
