"use client";

import { motion, useMotionTemplate, useMotionValue, useSpring } from "framer-motion";
import { MouseEvent, useEffect, useState } from "react";
import { SplitText } from "@/components/ui/SplitText";
import { Particles } from "@/components/ui/Particles";

export function Hero() {
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  // Add a slight spring to the light tracker for cinematic fluidity
  const smoothMouseX = useSpring(mouseX, { stiffness: 50, damping: 20 });
  const smoothMouseY = useSpring(mouseY, { stiffness: 50, damping: 20 });

  function handleMouseMove({ currentTarget, clientX, clientY }: MouseEvent) {
    const { left, top } = currentTarget.getBoundingClientRect();
    mouseX.set(clientX - left);
    mouseY.set(clientY - top);
  }

  // Ensure initial render matches server by mounting effects only on client
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText("npm i -g @dhruv2mars/gunmetal");
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <section 
      className="relative min-h-[100vh] w-full flex flex-col items-center justify-center overflow-hidden pt-32 pb-24"
      onMouseMove={handleMouseMove}
      style={{ background: "var(--bg)" }}
    >
      {/* 1. Base Layer: The Void (Particles) */}
      {mounted && <Particles />}

      {/* 2. Middle Layer: Spring-tracked cinematic spotlight */}
      <motion.div
        className="pointer-events-none absolute inset-0 transition duration-300 z-0 opacity-80 mix-blend-screen"
        style={{
          background: useMotionTemplate`
            radial-gradient(
              800px circle at ${smoothMouseX}px ${smoothMouseY}px,
              rgba(250, 249, 246, 0.04),
              transparent 70%
            )
          `,
        }}
      />

      <div className="relative z-10 container mx-auto px-6 flex flex-col items-center text-center">
        {/* Majestic Typography using SplitText for staggered cinematic reveal */}
        <h1 
          className="mb-8 max-w-[1000px] text-[52px] sm:text-[64px] md:text-[88px] font-normal leading-[0.95] tracking-[-0.04em] text-[#faf9f6]"
          style={{ fontFamily: "var(--font-matter)" }}
        >
          <SplitText className="block text-[#faf9f6]" delay={0.1}>
            The middleman layer
          </SplitText>
          <SplitText className="block text-[#868584] mt-2 md:mt-0" delay={0.3}>
            for AI inference.
          </SplitText>
        </h1>

        <motion.p
          initial={{ opacity: 0, y: 15, filter: "blur(4px)" }}
          animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
          transition={{ duration: 1.2, delay: 0.6, ease: [0.16, 1, 0.3, 1] }}
          className="mx-auto mb-14 max-w-[680px] text-[18px] md:text-[22px] text-[#afaeac] leading-[1.5] tracking-[-0.01em]"
          style={{ fontFamily: "var(--font-matter)" }}
        >
          Use AI subscriptions as upstream providers for inference.
        </motion.p>

        {/* Copy Command Box */}
        <motion.div
          initial={{ opacity: 0, y: 15 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1, delay: 0.8, ease: [0.16, 1, 0.3, 1] }}
          className="relative z-20 flex justify-center w-full"
        >
          <button 
            onClick={handleCopy}
            className="group flex items-center justify-between gap-4 rounded-xl border border-[rgba(226,226,226,0.15)] bg-[#111110] px-6 py-4 transition-all hover:bg-[#161615] hover:border-[rgba(226,226,226,0.3)] shadow-[0_0_30px_-10px_rgba(0,0,0,0.5)] w-full max-w-[420px]"
          >
            <div className="flex items-center gap-4 overflow-hidden">
              <span className="text-[#868584] font-mono text-[15px] select-none">$</span>
              <span className="text-[#faf9f6] font-mono text-[15px] truncate">npm i -g @dhruv2mars/gunmetal</span>
            </div>
            <div className="flex-shrink-0 text-[#868584] group-hover:text-[#faf9f6] transition-colors relative h-5 w-5">
              <motion.div
                initial={false}
                animate={{ opacity: copied ? 1 : 0, scale: copied ? 1 : 0.8 }}
                className="absolute inset-0 flex items-center justify-center text-[#27c93f]"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" />
                </svg>
              </motion.div>
              <motion.div
                initial={false}
                animate={{ opacity: copied ? 0 : 1, scale: copied ? 0.8 : 1 }}
                className="absolute inset-0 flex items-center justify-center"
              >
                <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
                </svg>
              </motion.div>
            </div>
          </button>
        </motion.div>
      </div>
    </section>
  );
}

