      style={{ background: "var(--bg)" }}
    >
      <FilmGrain />

      {/* 
        ========================================================================
        THE ECLIPSE (The Physical Middleman)
        ========================================================================
      */}
      <motion.div 
        style={{ y: yEclipse }}
        className="absolute inset-0 flex items-center justify-center pointer-events-none z-0"
      >
        <div className="relative w-[800px] h-[800px] flex items-center justify-center">

          {/* 1. The Blinding Chaos (Upstream Providers) - Hidden behind the proxy */}
          {/* A slow rotating, chaotic conic gradient that represents raw API energy */}
          <motion.div 
            animate={{ rotate: 360 }}
            transition={{ duration: 60, repeat: Infinity, ease: "linear" }}
            className="absolute inset-0 rounded-full opacity-[0.15]"
            style={{
              background: "conic-gradient(from 0deg, transparent 0%, rgba(250,249,246,0.8) 10%, transparent 30%, rgba(250,249,246,0.4) 60%, transparent 80%, rgba(250,249,246,1) 100%)",
              filter: "blur(60px)",
              transform: "scale(1.1)",
            }}
          />

          {/* 2. The Corona (The Unified Light passing around the proxy) */}
          <div 
            className="absolute inset-0 rounded-full"
            style={{
              boxShadow: `
                0 0 120px 20px rgba(250,249,246, 0.05),
                0 0 250px 40px rgba(250,249,246, 0.02)
              `,
            }}
          />

          {/* 3. The Gunmetal Proxy (The Solid Sphere blocking the chaos) */}
          <motion.div 
            initial={{ scale: 0.8, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ duration: 2, ease: [0.16, 1, 0.3, 1] }}
            className="absolute w-[500px] h-[500px] rounded-full z-10"
            style={{
              background: "var(--bg)",
              // Inner rim light to give it physical volume and separate it from the void
              boxShadow: "inset 0 0 0 1px rgba(250,249,246,0.06), inset 0 20px 40px -20px rgba(250,249,246,0.04)",
              // Outer eclipse shadow carving into the corona
              filter: "drop-shadow(0 0 40px rgba(0,0,0,0.8))"
            }}
          />
        </div>
      </motion.div>

      {/* 
        ========================================================================
        THE FOREGROUND (Typography & Actions)
        ========================================================================
      */}
      <motion.div 
        style={{ y: yText, opacity: opacityText }}
        className="relative z-20 container mx-auto px-6 flex flex-col items-center text-center mt-[-10vh]"
      >
        {/* Massive, Monumental Typography centered exactly over the dark sphere */}
        <motion.h1 
          initial={{ opacity: 0, y: 30, filter: "blur(8px)" }}
          animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
          transition={{ duration: 1.8, delay: 0.5, ease: [0.16, 1, 0.3, 1] }}
          className="mb-8 max-w-[1000px] text-[56px] sm:text-[72px] md:text-[96px] font-normal leading-[0.92] tracking-[-0.04em] text-[#faf9f6]"
          style={{ fontFamily: "var(--font-matter)" }}
        >
          <span className="block drop-shadow-[0_0_30px_rgba(250,249,246,0.3)]">The middleman layer</span>
          <span className="block text-[#868584] mix-blend-screen">for AI inference.</span>
        </motion.h1>

        <motion.p
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1.5, delay: 0.9, ease: [0.16, 1, 0.3, 1] }}
          className="mx-auto mb-16 max-w-[600px] text-[18px] md:text-[22px] text-[#afaeac] leading-[1.5] tracking-[-0.01em]"
          style={{ fontFamily: "var(--font-matter)" }}
        >
          Use AI subscriptions as upstream providers for inference.
        </motion.p>

        {/* Utilitarian, Flat Command Box */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1.5, delay: 1.1, ease: [0.16, 1, 0.3, 1] }}
          className="flex justify-center w-full"
        >
          <button 
            onClick={handleCopy}
            className="group relative flex items-center justify-between gap-6 rounded-[6px] border border-[rgba(250,249,246,0.12)] bg-[rgba(0,0,0,0.2)] backdrop-blur-md px-6 py-[18px] transition-all duration-500 hover:border-[rgba(250,249,246,0.3)] hover:bg-[rgba(250,249,246,0.03)] w-full max-w-[440px] cursor-pointer overflow-hidden"
          >
            {/* Subtle hover glow passing behind text */}
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-[rgba(250,249,246,0.05)] to-transparent -translate-x-[100%] group-hover:animate-[shimmer_2s_infinite] pointer-events-none" />

            <div className="relative flex items-center gap-4 z-10">
              <span className="text-[#868584] font-mono text-[14px] select-none">$</span>
              <span className="text-[#faf9f6] font-mono text-[15px] tracking-tight">npm i -g @dhruv2mars/gunmetal</span>
            </div>

            <div className="relative flex-shrink-0 text-[#868584] group-hover:text-[#faf9f6] transition-colors h-4 w-4 z-10">
              <svg className="w-4 h-4 opacity-100 group-active:opacity-0 transition-opacity" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
              </svg>
            </div>
          </button>
        </motion.div>
      </motion.div>

      <style dangerouslySetInnerHTML={{__html: `
        @keyframes shimmer {
          100% { transform: translateX(100%); }
        }
      `}} />
    </section>
  );
}

